-    __ umullv(A[2], __ T2D, b_lows, __ T2S, a_vals, __ S, 2);
-    __ umull2v(A[3], __ T2D, b_lows, __ T4S, a_vals, __ S, 2);
+    neon_partial_mult_64(A, b_lows, a_vals, 0);
